package embedder

import (
	"context"
	"math"
	"testing"
)

func TestMockEmbedderDeterministic(t *testing.T) {
	m := NewMockEmbedder(768)

	v1, err := m.Embed(context.Background(), "test text", PurposeIndex)
	if err != nil {
		t.Fatal(err)
	}
	v2, err := m.Embed(context.Background(), "test text", PurposeIndex)
	if err != nil {
		t.Fatal(err)
	}

	if len(v1) != 768 {
		t.Fatalf("expected 768 dims, got %d", len(v1))
	}
	for i := range v1 {
		if v1[i] != v2[i] {
			t.Fatalf("vectors differ at index %d: %f != %f", i, v1[i], v2[i])
		}
	}
}

func TestMockEmbedderDifferentTexts(t *testing.T) {
	m := NewMockEmbedder(768)
	ctx := context.Background()

	v1, _ := m.Embed(ctx, "hello world", PurposeIndex)
	v2, _ := m.Embed(ctx, "goodbye world", PurposeIndex)

	// Vectors should differ for different texts
	same := true
	for i := range v1 {
		if v1[i] != v2[i] {
			same = false
			break
		}
	}
	if same {
		t.Error("vectors should differ for different texts")
	}
}

func TestMockEmbedderBatch(t *testing.T) {
	m := NewMockEmbedder(768)
	ctx := context.Background()

	texts := []string{"one", "two", "three"}
	vecs, err := m.EmbedBatch(ctx, texts, PurposeIndex)
	if err != nil {
		t.Fatal(err)
	}
	if len(vecs) != 3 {
		t.Fatalf("expected 3 vectors, got %d", len(vecs))
	}

	// Verify each batch result matches individual embed
	for i, text := range texts {
		single, _ := m.Embed(ctx, text, PurposeIndex)
		for j := range single {
			if single[j] != vecs[i][j] {
				t.Errorf("batch[%d] differs from single at index %d", i, j)
				break
			}
		}
	}
}

func TestMockEmbedderNormalised(t *testing.T) {
	m := NewMockEmbedder(768)
	v, _ := m.Embed(context.Background(), "test normalisation", PurposeIndex)

	var sumSq float64
	for _, val := range v {
		sumSq += float64(val) * float64(val)
	}
	norm := math.Sqrt(sumSq)
	if math.Abs(norm-1.0) > 0.01 {
		t.Errorf("vector norm = %f, expected ~1.0", norm)
	}
}

func TestMockEmbedderDimensions(t *testing.T) {
	m := NewMockEmbedder(384)
	if m.Dimensions() != 384 {
		t.Errorf("Dimensions() = %d, want 384", m.Dimensions())
	}
	if m.MaxTokens() != 8192 {
		t.Errorf("MaxTokens() = %d, want 8192", m.MaxTokens())
	}
}
